using System.IO;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly IWebHostEnvironment _environment;
        private readonly FileExtensionContentTypeProvider _contentTypeProvider;

        public FilesController(IWebHostEnvironment environment)
        {
            _environment = environment;
            _contentTypeProvider = new FileExtensionContentTypeProvider();
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
                return BadRequest("Filename is required.");

            var uploadsFolder = Path.Combine(_environment.ContentRootPath, "uploads");
            var filePath = Path.Combine(uploadsFolder, filename);

            var fullUploadsPath = Path.GetFullPath(uploadsFolder);
            var fullFilePath = Path.GetFullPath(filePath);

            if (!fullFilePath.StartsWith(fullUploadsPath, StringComparison.OrdinalIgnoreCase))
                return BadRequest("Invalid filename.");

            if (!System.IO.File.Exists(fullFilePath))
                return NotFound();

            if (!_contentTypeProvider.TryGetContentType(fullFilePath, out var contentType))
                contentType = "application/octet-stream";

            var fileStream = new FileStream(fullFilePath, FileMode.Open, FileAccess.Read, FileShare.Read);
            return File(fileStream, contentType, Path.GetFileName(fullFilePath));
        }
    }
